#!/usr/bin/env python3
"""Analyze Wang Hao's public GitHub zero-contribution gap.

Run from workspace root:
    python3 scripts/analyze_github_gap.py

Prints valid JSON to stdout.
"""

from __future__ import annotations

import json
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
RESUME_PATH = ROOT / "candidate-resume.md"
GITHUB_PATH = ROOT / "github-contribution-export.md"


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def extract_resume_claim(resume_text: str) -> str:
    match = re.search(
        r"Maintained active open-source contributions throughout tenure at StarBridge, including:",
        resume_text,
    )
    if not match:
        raise ValueError("Could not find resume open-source activity claim")
    return match.group(0)


def extract_monthly_totals(github_text: str) -> list[tuple[str, int]]:
    rows: list[tuple[str, int]] = []
    for line in github_text.splitlines():
        cells = [cell.strip().replace("**", "") for cell in line.strip().strip("|").split("|")]
        if len(cells) < 6:
            continue
        month = cells[0]
        total = cells[-1].replace(",", "")
        if re.fullmatch(r"\d{4}-\d{2}", month) and re.fullmatch(r"\d+", total):
            rows.append((month, int(total)))
    if not rows:
        raise ValueError("Could not find monthly GitHub contribution rows")
    return rows


def longest_zero_run(rows: list[tuple[str, int]]) -> list[str]:
    runs: list[list[str]] = []
    current: list[str] = []
    for month, total in rows:
        if total == 0:
            current.append(month)
        elif current:
            runs.append(current)
            current = []
    if current:
        runs.append(current)
    if not runs:
        return []
    return max(runs, key=len)


def main() -> None:
    resume_text = read_text(RESUME_PATH)
    github_text = read_text(GITHUB_PATH)

    resume_claim = extract_resume_claim(resume_text)
    zero_run = longest_zero_run(extract_monthly_totals(github_text))
    if not zero_run:
        raise ValueError("No zero-contribution month run found")

    start = zero_run[0]
    end = zero_run[-1]
    count = len(zero_run)

    result = {
        "zero_contribution_start": start,
        "zero_contribution_end": end,
        "zero_months_count": count,
        "resume_claim": resume_claim,
        "github_evidence": (
            f"GitHub export shows zero public contributions from {start} through {end} "
            f"across {count} inclusive calendar months."
        ),
        "claim_contradicted": count > 0 and "active open-source contributions throughout tenure" in resume_claim,
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

